class VisualAIAgent:
    async def process_visual_task(self, task, visual_inputs):
        # Analyze each visual input
        analyses = []
        for visual in visual_inputs:
            analysis = await self.mm_llm.analyze(
                prompt=f'Task: {task}\nAnalyze this {visual.type}',
                image=visual.data
            )
            analyses.append(analysis)

        # Combine visual analyses with task
        return await self.solve_with_visual_context(
            task, analyses
        )

# Use cases: UI debugging, document processing,
# video analysis, security monitoring
